import React, { Component } from "react";
import { Icon } from "antd";
import { connect } from "react-redux";

class Index extends Component {
  render() {
    return (
      <div
        style={{
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          flexDirection: "row",
          height: "95vh",
          paddingBottom: "5vh"
        }}
      >
        <img style={{ width: "30%" }} src={"/static/face.png"} />
        <div
          style={{
            display: "flex",
            flexDirection: "column"
          }}
        >
          <div>
            <div
              style={{
                fontWeight: "bold",
                fontSize: "6vw"
              }}
            >
              Greetings.
            </div>
            <div
              style={{
                textAlign: "center",
                fontSize: "1.2vw"
              }}
            >
              Soy Jackie.
            </div>
          </div>

          <div
            style={{
              display: "flex",
              justifyContent: "space-around",
              alignItems: "center",
              marginTop: "2vw",
              width: "100%"
            }}
          >
            <Icon
              onClick={() =>
                window.open("https://github.com/jackien1", "_blank")
              }
              type="github"
              style={{ fontSize: "2vw" }}
            />
            <Icon
              onClick={() =>
                window.open(
                  "https://www.linkedin.com/in/jackie-ni-99b07016a/",
                  "_blank"
                )
              }
              type="linkedin"
              style={{ fontSize: "2vw" }}
            />
          </div>
        </div>
      </div>
    );
  }
}

const mapStateToProps = state => {
  const { batmode } = state.theme;
  return { batmode };
};

export default connect(
  mapStateToProps,
  { changeBatmode }
)(Index);
